import{_ as r,o as t,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F14: 負債結構與償債壓力測試","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F14_負債結構與償債壓力測試_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F14_負債結構與償債壓力測試_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/財務組/F14_負債結構與償債壓力測試_投資研究員.md"};function s(l,o,a,g,c,d){return t(),e("div",null,[...o[0]||(o[0]=[n('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f14-負債結構與償債壓力測試" tabindex="-1">F14: 負債結構與償債壓力測試 <a class="header-anchor" href="#f14-負債結構與償債壓力測試" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F14</li><li><strong>題目：</strong> 負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「信用風險 (Credit Risk)」與「資本結構優化」。擅長壓力測試（Stress Testing），能模擬營收下滑時企業的債務違約風險，是保護資本免於企業財務崩潰的第一道防線。</li><li><strong>意圖：</strong> 執行「財務穩健度與違約風險審計」。分析債務的結構（長短債比例）與利息負擔，判定在高息環境下的財務彈性，識別潛在的流動性危機與信用評等調降風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockBalanceSheet</code> 提取 <code>TotalLiabilities</code>、<code>ShortTermBorrowings</code>、<code>LongTermBorrowings</code>；調用 <code>TaiwanStockFinancialStatements</code> 提取 <code>InterestExpense</code> 與 <code>OperatingIncome</code> (EBIT)。</li><li><strong>【外部事實確認：公開資訊觀測站 (MOPS)】</strong>：檢索「[公司名] 債券發行」、「[公司名] 聯貸 規模」。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱「財務報告附註 -&gt; 借款」明細，核實借款利率區間與抵押資產。</li></ol></li><li><strong>邏輯：</strong> 執行「利息保障倍數 (ICR) 壓力測試」——分析 EBIT / 利息支出之安全性；執行「債務到期梯次分析」——判定未來 12 個月內的還款壓力。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>取數據</strong>：<code>python3 數據採集器.py balance_sheet [股號]</code> → 抓 ShortTermBorrowings、LongTermBorrowings</li><li><strong>計算</strong>：負債比、流動比、速動比、利息保障倍數</li><li><strong>壓力測試</strong>：利率上升 1% 對 EPS 的影響</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具提取「借款附註」</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①答詢詳解 ≥200 字；②空頭視角 ≥2 個；③要計算出具體的償債比率</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【債務事實優先】</strong>：智慧體<strong>必須</strong>列出最近 4 季的「負債比率」與「利息覆蓋倍數」。嚴禁在未列出利息支出前給予「財務健全」之定性。</li><li><strong>【高息承受度演算】</strong>：智慧體必須模擬若利率上升 100 點 (1%)，對 EPS 的稀釋程度。</li><li><strong>【短期流動性核實】</strong>：比對「現金及約當現金」與「一年內到期之長短期債務」。若缺口大於 20%，必須強制標註「具備再融資壓力」或「流動性風險」。</li><li><strong>【描述指標】</strong>：絕對禁用「負債適中」、「還款無虞」。必須量化為具體的「淨債務/EBITDA 比率」、「利息保障倍數」與「短債佔比 %」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f14-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F14 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f14-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F14 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「槓桿水位+保障能力」結構（例：負債比為 X%，利息保障倍數 Y，在高利率環境下 [防禦力強/脆弱]，還款壓力點位於 [短期/長期]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：淨債務為負（現金多於債務）或利息保障倍數高於 15，具備極強的信用額度與利率抵禦力，財務結構極其穩健。</li><li><strong>A (良)</strong>：負債比率穩定於產業中位數，現金流入足以支撐定期還本付息，財務槓桿運用得當。</li><li><strong>B (持平)</strong>：利息保障倍數低於 3，且短期內有大規模債務到期，面臨嚴重的利息侵蝕獲利與再融資困難風險。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>financial</code> 數據項與財報附註之借款利率表。</li></ul>',12)])])}const m=r(i,[["render",s]]);export{h as __pageData,m as default};
